use std::path::PathBuf;
use std::process::ExitCode;

use clap::Parser;

mod input;
mod replacer;
mod utils;

#[derive(Parser, Debug)]
#[command(
    name = "sd",
    version = "1.0.0",
    about = "An intuitive find & replace CLI",
    help_template = "{name} v{version}\n{about-with-newline}\n{usage-heading} {usage}\n\n{all-args}{after-help}",
    disable_help_flag = true,
    disable_version_flag = true,
)]
struct Args {
    /// Display changes in a human reviewable format (the specifics of the format are likely to change in the future)
    #[arg(short = 'p', long = "preview")]
    preview: bool,

    /// Treat FIND and REPLACE_WITH args as literal strings
    #[arg(short = 'F', long = "fixed-strings")]
    fixed_strings: bool,

    /// Limit the number of replacements that can occur per file. 0 indicates unlimited replacements
    ///
    /// [default: 0]
    #[arg(short = 'n', long = "max-replacements", value_name = "LIMIT", default_value_t = 0, hide_default_value = true)]
    max_replacements: usize,

    /// Regex flags. May be combined (like `-f mc`).
    ///
    /// c - case-sensitive
    ///
    /// e - disable multi-line matching
    ///
    /// i - case-insensitive
    ///
    /// m - multi-line matching
    ///
    /// s - make `.` match newlines
    ///
    /// w - match full words only
    #[arg(short = 'f', long = "flags", value_name = "FLAGS")]
    flags: Option<String>,

    /// Print help (see more with '--help')
    #[arg(short = 'h', long = "help", action = clap::ArgAction::Help)]
    help: Option<bool>,

    /// Print version
    #[arg(short = 'V', long = "version", action = clap::ArgAction::Version)]
    version: Option<bool>,

    /// The regexp or string (if using `-F`) to search for
    find: String,

    /// What to replace each match with. Unless in string mode, you may use captured values like $1, $2, etc
    replace_with: String,

    /// The path to file(s). This is optional - sd can also read from STDIN.
    ///
    /// Note: sd modifies files in-place by default. See documentation for examples.
    files: Vec<PathBuf>,
}

fn main() -> ExitCode {
    let args = Args::parse();
    match run(args) {
        Ok(()) => ExitCode::SUCCESS,
        Err(e) => {
            eprintln!("error: {}", e);
            ExitCode::from(1)
        }
    }
}

fn run(args: Args) -> Result<(), utils::Error> {
    let replacer = replacer::Replacer::new(
        args.find,
        args.replace_with,
        args.fixed_strings,
        args.flags,
        if args.max_replacements == 0 { None } else { Some(args.max_replacements) },
    )?;
    let source = input::Source::new(&args.files);
    source.apply(&replacer, args.preview)?;
    Ok(())
}

