use thiserror::Error;

#[derive(Debug, Error)]
pub enum Error {
    #[error("invalid regex {0}")]
    InvalidRegex(#[from] regex::Error),
    #[error("invalid path: {0}")]
    InvalidPath(PathBuf),
    #[error("{0}")]
    Io(#[from] std::io::Error),
    #[error("Failed processing some inputs\n{0}")]
    FailedProcessing(String),
}

