use crate::utils::Error;
use regex::bytes::{Regex, RegexBuilder};

pub struct Replacer {
    regex: Regex,
    replace_with: Vec<u8>,
    fixed_strings: bool,
    max_replacements: Option<usize>,
}

impl Replacer {
    pub fn new(
        look_for: String,
        replace_with: String,
        is_fixed_strings: bool,
        flags: Option<String>,
        max_replacements: Option<usize>,
    ) -> Result<Self, Error> {
        let (find_pat, processed_replace, multi_line_default) =
            Self::build_pattern_and_replacement(&look_for, &replace_with, is_fixed_strings, &flags);

        let mut builder = RegexBuilder::new(&find_pat);
        builder.multi_line(multi_line_default);

        if let Some(flag_str) = &flags {
            for c in flag_str.chars() {
                match c {
                    'c' => {
                        builder.case_insensitive(false);
                    }
                    'i' => {
                        builder.case_insensitive(true);
                    }
                    'e' => {
                        builder.multi_line(false);
                    }
                    'm' => {
                        // No-op: default already has multi_line set; further m re-confirms.
                        // We do NOT call multi_line(true) here, because experimentally
                        // any 'e' in flags wins regardless of position.
                    }
                    's' => {
                        builder.dot_matches_new_line(true);
                    }
                    'w' => {
                        // handled in build_pattern
                    }
                    _ => {}
                }
            }
        }

        let regex = builder.build()?;

        Ok(Self {
            regex,
            replace_with: processed_replace,
            fixed_strings: is_fixed_strings,
            max_replacements,
        })
    }

    fn build_pattern_and_replacement(
        look_for: &str,
        replace_with: &str,
        is_fixed_strings: bool,
        flags: &Option<String>,
    ) -> (String, Vec<u8>, bool) {
        let pattern = if is_fixed_strings {
            regex::escape(look_for)
        } else {
            look_for.to_string()
        };

        // Apply 'w' flag: wrap pattern in word boundaries
        let pattern = if let Some(f) = flags {
            if f.contains('w') {
                format!(r"\b(?:{})\b", pattern)
            } else {
                pattern
            }
        } else {
            pattern
        };

        // Process replacement string
        let processed_replace = if is_fixed_strings {
            replace_with.as_bytes().to_vec()
        } else {
            process_replacement_escapes(replace_with)
        };

        // multi_line default is true unless 'e' is in flags
        // BUT we set the builder default and let the loop override
        let multi_line_default = true;

        (pattern, processed_replace, multi_line_default)
    }

    pub fn replace<'a>(&'a self, content: &'a [u8]) -> std::borrow::Cow<'a, [u8]> {
        if self.fixed_strings {
            self.replace_fixed(content)
        } else {
            // For regex mode, the replacement needs special $N handling via regex crate
            // But we already preprocessed escape sequences, so call replace with our bytes
            // as a Replacer that processes $N
            let limit = self.max_replacements.unwrap_or(0);
            if limit == 0 {
                self.regex.replace_all(content, &self.replace_with[..])
            } else {
                self.regex.replacen(content, limit, &self.replace_with[..])
            }
        }
    }

    fn replace_fixed<'a>(&'a self, content: &'a [u8]) -> std::borrow::Cow<'a, [u8]> {
        // -F mode: literal find, literal replace (no $N expansion)
        let limit = self.max_replacements.unwrap_or(0);
        if limit == 0 {
            self.regex
                .replace_all(content, regex::bytes::NoExpand(&self.replace_with[..]))
        } else {
            self.regex
                .replacen(content, limit, regex::bytes::NoExpand(&self.replace_with[..]))
        }
    }
}

fn process_replacement_escapes(s: &str) -> Vec<u8> {
    let bytes = s.as_bytes();
    let mut out = Vec::with_capacity(bytes.len());
    let mut i = 0;
    while i < bytes.len() {
        let b = bytes[i];
        if b == b'\\' && i + 1 < bytes.len() {
            let next = bytes[i + 1];
            match next {
                b'n' => {
                    out.push(b'\n');
                    i += 2;
                }
                b'r' => {
                    out.push(b'\r');
                    i += 2;
                }
                b't' => {
                    out.push(b'\t');
                    i += 2;
                }
                b'\\' => {
                    out.push(b'\\');
                    i += 2;
                }
                b'x' => {
                    // expect exactly 2 hex digits
                    if i + 3 < bytes.len()
                        && is_hex(bytes[i + 2])
                        && is_hex(bytes[i + 3])
                    {
                        let hi = hex_val(bytes[i + 2]);
                        let lo = hex_val(bytes[i + 3]);
                        let codepoint = (hi << 4) | lo;
                        // encode as UTF-8 (codepoint up to 0xFF here)
                        let ch = char::from_u32(codepoint as u32).unwrap();
                        let mut buf = [0u8; 4];
                        let encoded = ch.encode_utf8(&mut buf);
                        out.extend_from_slice(encoded.as_bytes());
                        i += 4;
                    } else {
                        out.push(b);
                        i += 1;
                    }
                }
                _ => {
                    out.push(b);
                    i += 1;
                }
            }
        } else {
            out.push(b);
            i += 1;
        }
    }
    out
}

fn is_hex(b: u8) -> bool {
    matches!(b, b'0'..=b'9' | b'a'..=b'f' | b'A'..=b'F')
}

fn hex_val(b: u8) -> u8 {
    match b {
        b'0'..=b'9' => b - b'0',
        b'a'..=b'f' => b - b'a' + 10,
        b'A'..=b'F' => b - b'A' + 10,
        _ => 0,
    }
}

