use std::io::{self, Read, Write};
use std::path::PathBuf;

use crate::replacer::Replacer;
use crate::utils::Error;

pub struct Source<'a> {
    files: &'a [PathBuf],
}

impl<'a> Source<'a> {
    pub fn new(files: &'a [PathBuf]) -> Self {
        Self { files }
    }

    pub fn apply(&self, replacer: &Replacer, preview: bool) -> Result<(), Error> {
        if self.files.is_empty() {
            return self.apply_stdin(replacer);
        }

        // Validate all paths first (exists check)
        for path in self.files {
            if !path.exists() {
                return Err(Error::InvalidPath(path.clone()));
            }
        }

        if preview {
            self.apply_preview(replacer)
        } else {
            self.apply_files(replacer)
        }
    }

    fn apply_stdin(&self, replacer: &Replacer) -> Result<(), Error> {
        let mut buf = Vec::new();
        io::stdin().lock().read_to_end(&mut buf)?;
        let result = replacer.replace(&buf);
        let mut stdout = io::stdout().lock();
        stdout.write_all(&result)?;
        stdout.flush()?;
        Ok(())
    }

    fn apply_preview(&self, replacer: &Replacer) -> Result<(), Error> {
        let mut stdout = io::stdout().lock();
        let show_headers = self.files.len() > 1;
        for path in self.files {
            let content = read_file(path)?;
            let result = replacer.replace(&content);
            if show_headers {
                stdout.write_all(format!("----- FILE {} -----\n", path.display()).as_bytes())?;
            }
            stdout.write_all(&result)?;
        }
        stdout.flush()?;
        Ok(())
    }

    fn apply_files(&self, replacer: &Replacer) -> Result<(), Error> {
        let mut errors: Vec<String> = Vec::new();
        for path in self.files {
            if let Err(e) = process_file(path, replacer) {
                errors.push(format!("    {}: {}", path.display(), e));
            }
        }
        if !errors.is_empty() {
            // For a single failure with simple OS error, we may want to surface as-is.
            // But the reference for single dir/special file shows just the raw OS error.
            // For batch failures with multiple files, it wraps with "Failed processing some inputs".
            if self.files.len() == 1 || errors.len() == 1 {
                // Single-file failure: report the raw OS error
                // Strip the leading "    PATH: " prefix
                let raw = errors[0]
                    .splitn(2, ": ")
                    .nth(1)
                    .unwrap_or(&errors[0])
                    .to_string();
                return Err(Error::Io(io::Error::new(io::ErrorKind::Other, raw)));
            }
            return Err(Error::FailedProcessing(errors.join("\n")));
        }
        Ok(())
    }
}

fn read_file(path: &std::path::Path) -> Result<Vec<u8>, io::Error> {
    use memmap2::Mmap;
    let file = std::fs::File::open(path)?;
    // Use mmap if possible — falls back to direct read on failure
    let mmap = unsafe { Mmap::map(&file)? };
    Ok(mmap.to_vec())
}

fn process_file(path: &std::path::Path, replacer: &Replacer) -> Result<(), io::Error> {
    let content = read_file(path)?;
    let result = replacer.replace(&content);

    // Write atomically: write to temp file in same dir, then rename.
    let parent = path.parent().unwrap_or_else(|| std::path::Path::new("."));
    let mut tmp = tempfile::NamedTempFile::new_in(parent)?;
    tmp.write_all(&result)?;
    tmp.flush()?;

    // Preserve permissions
    let metadata = std::fs::metadata(path)?;
    let perms = metadata.permissions();
    std::fs::set_permissions(tmp.path(), perms)?;

    tmp.persist(path).map_err(|e| e.error)?;
    Ok(())
}

